<template><div class="report" v-loading="loading"><header><div><p class="eyebrow">PERSONAL LEARNING ANALYTICS</p><h1>我的学习报告</h1><p>数据更新于 {{formatTime(data.generatedAt)}}</p></div><el-button @click="load">刷新数据</el-button></header><section class="metrics"><article><span>学习时长</span><strong>{{hours}}<small> 小时</small></strong><em>累计视频与PDF学习</em></article><article><span>课程进度</span><strong>{{data.completedCourses||0}}<small> / {{data.enrolledCourses||0}}</small></strong><em>已完成 / 已选课程</em></article><article><span>作业平均分</span><strong>{{number(data.averageScore)}}<small> 分</small></strong><em>已批改 {{data.completedHomework||0}} 份</em></article><article><span>训练表现</span><strong>{{number(data.trainingAverage)}}<small> 分</small></strong><em>完成 {{data.trainingCount||0}} 次训练</em></article></section>
<section class="grid"><div class="panel progress-panel"><div class="title"><div><h2>课程学习进度</h2><p>追踪每门已选课程的学习完成情况</p></div></div><el-empty v-if="!data.courseProgress?.length" description="暂无课程学习记录"/><div v-for="c in data.courseProgress" :key="c.courseId" class="course"><div><b>{{c.courseName}}</b><span>{{c.studiedLessons}} 个小节 · {{duration(c.studySeconds)}}</span></div><el-progress :percentage="Number(c.progress||0)" :stroke-width="10" :color="progressColor"/><el-button type="primary" size="small" @click="study(c.courseId)">继续学习</el-button></div></div><div class="panel chart-panel"><div class="title"><div><h2>近30日学习趋势</h2><p>每日学习分钟数</p></div></div><div ref="studyChart" class="chart"/><el-empty v-if="!data.studyTrend?.dates?.length" description="暂无学习时长数据"/></div></section>
<section class="panel"><div class="title"><div><h2>成绩与正确率</h2><p>线上作业、线下考试及客观题正确率变化</p></div></div><div class="score-layout"><div ref="scoreChart" class="chart large"/><el-table :data="data.scoreHistory||[]" empty-text="暂无成绩记录"><el-table-column prop="name" label="考核" min-width="140"/><el-table-column prop="courseName" label="课程"/><el-table-column label="成绩" width="100"><template #default="{row}"><b>{{row.score}} / {{row.totalScore}}</b></template></el-table-column><el-table-column label="类型" width="90"><template #default="{row}">{{row.scoreType==='homework'?'线上作业':'线下考试'}}</template></el-table-column></el-table></div></section>
 </div></template>
<script setup>import{computed,nextTick,onBeforeUnmount,onMounted,ref}from'vue';import{useRouter}from'vue-router';import*as echarts from'echarts';import{getLearningReport}from'../../api/analysis.js';const router=useRouter(),loading=ref(false),data=ref({}),studyChart=ref(),scoreChart=ref();let charts=[];const hours=computed(()=>(Number(data.value.totalStudyTime||0)/3600).toFixed(1));const number=v=>Number(v||0).toFixed(1),duration=s=>Number(s||0)>=3600?`${(Number(s)/3600).toFixed(1)}小时`:`${Math.round(Number(s||0)/60)}分钟`,formatTime=v=>v?new Date(v).toLocaleString():'-',study=id=>router.push(`/student/study/${id}`),progressColor=p=>p<40?'#f56c6c':p<80?'#e6a23c':'#22c55e';function clear(){charts.forEach(x=>x.dispose());charts=[]}function init(){clear();if(studyChart.value&&data.value.studyTrend?.dates?.length){const c=echarts.init(studyChart.value);c.setOption({tooltip:{trigger:'axis'},grid:{left:45,right:20,top:25,bottom:30},xAxis:{type:'category',data:data.value.studyTrend.dates},yAxis:{type:'value',name:'分钟'},series:[{type:'line',smooth:true,data:data.value.studyTrend.values,areaStyle:{color:'rgba(79,70,229,.12)'},lineStyle:{color:'#4f46e5',width:3},itemStyle:{color:'#4f46e5'}}]});charts.push(c)}if(scoreChart.value){const t=data.value.accuracyTrend||{};const c=echarts.init(scoreChart.value);c.setOption({tooltip:{trigger:'axis'},grid:{left:45,right:20,top:25,bottom:30},xAxis:{type:'category',data:t.dates||[]},yAxis:{type:'value',min:0,max:100,name:'正确率%'},series:[{type:'bar',data:t.values||[],itemStyle:{color:'#14b8a6',borderRadius:[6,6,0,0]}}]});charts.push(c)}}async function load(){loading.value=true;try{data.value=await getLearningReport();await nextTick();init()}finally{loading.value=false}}const resize=()=>charts.forEach(x=>x.resize());onMounted(()=>{load();window.addEventListener('resize',resize)});onBeforeUnmount(()=>{clear();window.removeEventListener('resize',resize)})</script>
<style scoped>.report{max-width:1400px;margin:auto;color:#18212f}.report header{display:flex;justify-content:space-between;align-items:flex-end;margin-bottom:24px}.report h1{font-size:30px;margin:4px 0}.report header p{margin:0;color:#8491a5}.eyebrow{font-size:12px!important;letter-spacing:1.6px;color:#4f46e5!important;font-weight:700}.metrics{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin-bottom:18px}.metrics article,.panel{background:#fff;border:1px solid #edf0f5;border-radius:16px;box-shadow:0 8px 28px rgba(31,41,55,.05)}.metrics article{padding:20px;display:grid;gap:8px}.metrics span,.metrics em,.title p,.course span{color:#8491a5;font-style:normal;font-size:13px}.metrics strong{font-size:30px}.metrics small{font-size:14px;font-weight:500}.grid{display:grid;grid-template-columns:1.2fr 1fr;gap:18px}.panel{padding:22px;margin-bottom:18px}.title{display:flex;justify-content:space-between;align-items:center;margin-bottom:18px}.title h2{margin:0 0 5px;font-size:19px}.title p{margin:0}.course{display:grid;grid-template-columns:minmax(180px,1fr) minmax(180px,1.5fr) 80px;gap:16px;align-items:center;padding:14px 0;border-bottom:1px solid #f0f2f5}.course>div:first-child{display:grid;gap:5px}.chart{height:280px}.score-layout{display:grid;grid-template-columns:1fr 1.2fr;gap:24px}.chart.large{height:320px}@media(max-width:1050px){.metrics{grid-template-columns:repeat(2,1fr)}.grid,.score-layout{grid-template-columns:1fr}}@media(max-width:640px){.metrics{grid-template-columns:1fr}.report header{align-items:flex-start;gap:12px}.course{grid-template-columns:1fr}}</style>
